            subheadline: { type: Type.STRING },
            price:       { type: Type.STRING },
            brandEn:     { type: Type.STRING },
            brandKo:     { type: Type.STRING },
          },
          required: ['headline', 'subheadline', 'price', 'brandEn', 'brandKo'],
